trigger.body:
	vCheck NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

	IF TG_OP IN ('INSERT','UPDATE') THEN
		SELECT COUNT(*) INTO vCheck FROM scrvro_vendor_route WHERE isactive='Y'
			AND scrvro_vendor_route_id!=:NEW.scrvro_vendor_route_id AND c_bpartner_id=:NEW.c_bpartner_id;
		IF vCheck > 0 AND :NEW.isactive='Y' THEN
			RAISE_APPLICATION_ERROR(-20000, '@Scrvro_VendorRouteActive@') ;
		END IF;
	END IF;

	END SCRVRO_VENDOR_ROUTE_TRG
